#!/usr/bin/env node

/**
 * Kaldor NPC Life Events
 *
 * Used by the aging engine to build NPC histories year by year.
 * Each year, one event is drawn from the eligible pool for the character's
 * class, age group, sex, and active conditions.
 *
 * EVENT STRUCTURE
 * ───────────────
 * id          {string}   Unique identifier
 * label       {string}   Short display name
 * flavour     {object}   { male: string|null, female: string|null }
 *                        null = sex-exclusive to the other sex
 * classes     {string[]} Eligible social classes
 * ageGroups   {string[]} 'young' (18–35), 'middle' (36–60), 'old' (61+)
 * weights     {object}   { [class]: { [ageGroup]: number } }
 *                        Omitted class/age combinations default to 0 (ineligible)
 * sexWeightMod {object|null}
 *                        { male: N, female: N } — added to base weight per sex
 *                        null = no sex difference
 * requireConditions  {string[]}  All must be present on character (AND)
 * excludeConditions  {string[]}  None must be present (blocks event)
 * conditionWeightMods {object}   { [condition]: weightDelta } applied additively
 *
 * effects     {object}
 *   ops         {number}        Free OPs added to budget (counts against annual 3 OP max)
 *   skills      {Array|null}    [{ skill, ops }] — targeted OP allocation (from same budget)
 *   totalOPs    {number}        ops + sum(skills[].ops) — pre-calculated for budget checking
 *   attributes  {object|null}   { [key]: delta }  e.g. { STA: -1 }
 *   conditions  {object|null}   { add: string[], remove: string[] }
 *   classChange {object|null}   { to: string, note: string }
 *   deityChange {object|null}   { to: string, note: string }
 *
 * followOn    {Array}    [{ eventId, weightMod, duration }]
 *                        weightMod applied to that event's weight for `duration` years
 */

// ─────────────────────────────────────────────────────────────────────────────
// VALID VALUES REFERENCE
// ─────────────────────────────────────────────────────────────────────────────
