// HELPER — build a weight block quickly
// ─────────────────────────────────────────────────────────────────────────────
function w(classWeights) {
  // classWeights: { noble: { young: N, middle: N, old: N }, ... }
  // Omit age group to default to 0 for that group.
  return classWeights;
}

