    pool: 'biographical',
    isMajor: false,
    flavour: {
      male:   'He was posted to the garrison watching the Osel crossing. The first month he did not understand why everyone kept one hand near a weapon at all times. By the third month he understood.',
      female: 'She was assigned to the Oselmarch border. The garrison was small, the range was wide, and the Pagaelin were an omnipresent fact of life rather than an abstract threat. She learned to read the heath the way the long-service soldiers did — not as landscape but as communication.',
    },
