    weights: { guilded_miner: { young: 22, middle: 0, old: 0 } },
    sexWeightMod: null,
    requireConditions: [],
    excludeConditions: [],
    conditionWeightMods: {},
    phaseWeightMods: { apprentice: +18, journeyman: +4 },
    effects: null,
    followOn: [],
