// ─────────────────────────────────────────────────────────────────────────────
// SCHEMA VALIDATOR — runs at require() time, throws on any data bug
// ─────────────────────────────────────────────────────────────────────────────

(function validateLifeEvents() {
  const VALID_CLASSES    = new Set(['noble','merchant','warrior','soldier','peasant','artisan','clergy','unguilded','lia_kavair','priest_naveh','guilded_performer','guilded_courtesan','guilded_innkeeper','guilded_miner','guilded_mariner','guilded_physician','guilded_litigant','guilded_herald','guilded_arcanist','pagaelin','walker_shaman','destitute']);
  const VALID_AGE_GROUPS = new Set(['young','middle','old']);
  const VALID_POOLS      = new Set(['biographical','family','colour']);
  const knownConditions  = new Set(Object.keys(CONDITION_REGISTRY));
  // 'married' is a derived boolean (from spouses array) — not in CONDITION_REGISTRY
  // but valid in requireConditions/excludeConditions where the engine interprets it specially.
  knownConditions.add('married');
  const seenIds          = new Set();
  const errors           = [];

  for (const ev of LIFE_EVENTS) {
    const tag = ev.id || '(missing id)';

    // Required top-level fields
    // 'classes' is now optional — events use excludeClasses (blacklist) instead.
    // Either 'classes' OR 'excludeClasses' OR neither is acceptable.
    const requiredFields = ['id','label','pool','ageGroups','weights','effects','followOn'];
    for (const field of requiredFields) {
      if (ev[field] === undefined) errors.push(`${tag}: missing required field '${field}'`);
    }
    if (!ev.flavour || (ev.flavour.male === undefined && ev.flavour.female === undefined)) {
      errors.push(`${tag}: missing flavour object`);
    }

    // Unique IDs
    if (seenIds.has(ev.id)) {
      errors.push(`${ev.id}: DUPLICATE event id — second definition silently overwrites the first`);
    }
    seenIds.add(ev.id);

    // Valid pool
    if (!VALID_POOLS.has(ev.pool)) errors.push(`${tag}: unknown pool '${ev.pool}'`);

    // Valid classes (legacy whitelist) and excludeClasses (blacklist)
    for (const cls of (ev.classes || [])) {
      if (!VALID_CLASSES.has(cls)) errors.push(`${tag}: unknown class '${cls}'`);
    }
    for (const cls of (ev.excludeClasses || [])) {
      if (!VALID_CLASSES.has(cls)) errors.push(`${tag}: unknown class in excludeClasses '${cls}'`);
    }

    // Valid ageGroups
    for (const ag of (ev.ageGroups || [])) {
      if (!VALID_AGE_GROUPS.has(ag)) errors.push(`${tag}: unknown ageGroup '${ag}'`);
    }

    // minAge / maxAge sanity
    if (ev.minAge != null && (typeof ev.minAge !== 'number' || ev.minAge < 1)) {
      errors.push(`${tag}: minAge must be a positive number`);
    }
    if (ev.maxAge != null && (typeof ev.maxAge !== 'number' || ev.maxAge < 1)) {
      errors.push(`${tag}: maxAge must be a positive number`);
    }
    if (ev.minAge != null && ev.maxAge != null && ev.minAge > ev.maxAge) {
      errors.push(`${tag}: minAge (${ev.minAge}) > maxAge (${ev.maxAge})`);
    }

    // oceanWeightMod: must only reference valid OCEAN traits
    if (ev.oceanWeightMod != null) {
      const VALID_OCEAN = new Set(['O','C','E','A','N']);
      for (const trait of Object.keys(ev.oceanWeightMod)) {
        if (!VALID_OCEAN.has(trait)) errors.push(`${tag}: oceanWeightMod references unknown trait '${trait}'`);
      }
      for (const [trait, val] of Object.entries(ev.oceanWeightMod)) {
        if (typeof val !== 'number') errors.push(`${tag}: oceanWeightMod['${trait}'] must be a number`);
      }
    }

    // Condition references exist in registry
    for (const c of (ev.requireConditions || [])) {
      if (!knownConditions.has(c)) errors.push(`${tag}: requireConditions references unknown condition '${c}'`);
    }
    for (const c of (ev.excludeConditions || [])) {
      if (!knownConditions.has(c)) errors.push(`${tag}: excludeConditions references unknown condition '${c}'`);
    }
    for (const c of Object.keys(ev.conditionWeightMods || {})) {
      if (!knownConditions.has(c)) errors.push(`${tag}: conditionWeightMods references unknown condition '${c}'`);
    }
    for (const c of (ev.effects?.conditions?.add    || [])) {
      if (!knownConditions.has(c)) errors.push(`${tag}: effects.conditions.add references unknown condition '${c}'`);
    }
    for (const c of (ev.effects?.conditions?.remove || [])) {
      if (!knownConditions.has(c)) errors.push(`${tag}: effects.conditions.remove references unknown condition '${c}'`);
    }

    // totalOPs consistency
    if (ev.effects) {
      const declaredTotal = ev.effects.totalOPs ?? 0;
      const freeOPs       = ev.effects.ops       ?? 0;
      const skillSum      = (ev.effects.skills || []).reduce((s, sk) => s + (sk.ops || 0), 0);
      const computed      = freeOPs + skillSum;
      if (declaredTotal !== computed) {
        errors.push(`${tag}: totalOPs declared as ${declaredTotal} but ops(${freeOPs}) + skillSum(${skillSum}) = ${computed}`);
      }
    }

    // minGapYears must be a positive integer if present
    if (ev.minGapYears !== undefined && (typeof ev.minGapYears !== 'number' || ev.minGapYears < 1)) {
      errors.push(`${tag}: minGapYears must be a positive integer, got ${ev.minGapYears}`);
    }

    // followOn references — warn only (target events may not be listed yet)
    // This is a forward-reference problem so we collect and check after the loop.
  }

  // Cross-check followOn eventId references
  for (const ev of LIFE_EVENTS) {
    for (const fo of (ev.followOn || [])) {
      if (!seenIds.has(fo.eventId)) {
        errors.push(`${ev.id}: followOn references unknown eventId '${fo.eventId}'`);
      }
      if (typeof fo.weightMod !== 'number') {
        errors.push(`${ev.id}: followOn[${fo.eventId}].weightMod must be a number`);
      }
      if (typeof fo.duration !== 'number' || fo.duration < 1) {
        errors.push(`${ev.id}: followOn[${fo.eventId}].duration must be a positive integer`);
      }
    }
  }

  if (errors.length > 0) {
    throw new Error(
      `[life-events] Schema validation failed with ${errors.length} error(s):\n` +
      errors.map(e => `  • ${e}`).join('\n')
    );
  }
})();

// ─────────────────────────────────────────────────────────────────────────────
// QUICK STATS (node life-events.js)
// ─────────────────────────────────────────────────────────────────────────────

if (require.main === module) {
  console.log(`Total events: ${LIFE_EVENTS.length}`);

  // Count by class eligibility
  const classCounts = {};
  for (const e of LIFE_EVENTS) {
    for (const cls of (e.classes || [])) {
      classCounts[cls] = (classCounts[cls] || 0) + 1;
    }
  }
  console.log('\nEvents per class:');
  for (const [cls, n] of Object.entries(classCounts)) {
    console.log(`  ${cls.padEnd(14)} ${n}`);
  }

  // Sex-exclusive events
  const maleOnly   = LIFE_EVENTS.filter(e => e.flavour.female === null);
  const femaleOnly = LIFE_EVENTS.filter(e => e.flavour.male   === null);
  console.log(`\nMale-exclusive events:   ${maleOnly.length}   (${maleOnly.map(e=>e.id).join(', ')})`);
  console.log(`Female-exclusive events: ${femaleOnly.length}   (${femaleOnly.map(e=>e.id).join(', ')})`);

  // Events with follow-ons
  const withFollowOn = LIFE_EVENTS.filter(e => e.followOn.length > 0);
  console.log(`\nEvents with follow-ons: ${withFollowOn.length}`);

  // Events that change class
  const classChangers = LIFE_EVENTS.filter(e => e.effects.classChange);
  console.log(`Events that change class: ${classChangers.length}   (${classChangers.map(e=>e.id).join(', ')})`);

  // Age group coverage
  const ageCounts = { young: 0, middle: 0, old: 0 };
  for (const e of LIFE_EVENTS) {
    for (const ag of e.ageGroups) ageCounts[ag]++;
  }
  console.log(`\nEvents per age group:`);
  for (const [ag, n] of Object.entries(ageCounts)) {
    console.log(`  ${ag.padEnd(8)} ${n}`);
  }

}